import { useState } from "react";

import axios from "axios";

export default function Login() {

  const [form, setForm] = useState({
    role: "customer"
  });

  const login = async () => {

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        form
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (res.data.user.role === "customer") {

        window.location = "/customer";

      } else {

        window.location = "/labour";
      }

    } catch (err) {

      alert("Invalid Credentials");
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <h1 style={styles.heading}>
          Login
        </h1>

        <select
          style={styles.input}
          onChange={(e) =>
            setForm({
              ...form,
              role: e.target.value
            })
          }
        >

          <option value="customer">
            Customer
          </option>

          <option value="labour">
            Labour
          </option>

        </select>

        <input
          style={styles.input}
          placeholder="Email"
          onChange={(e) =>
            setForm({
              ...form,
              email: e.target.value
            })
          }
        />

        <input
          type="password"
          style={styles.input}
          placeholder="Password"
          onChange={(e) =>
            setForm({
              ...form,
              password: e.target.value
            })
          }
        />

        <button
          style={styles.btn}
          onClick={login}
        >
          Login
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    width: "380px",
    background: "white",
    padding: "35px",
    borderRadius: "18px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.06)"
  },

  heading: {
    marginBottom: "25px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd"
  },

  btn: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  }

};
